INSERT INTO `content` VALUES (1,'landing_title','Панель міста','City Panel'),(2,'landing_subtitle','    ПОРТАЛ ВІДКРИТИХ ДАНИХ','OPEN DATA PORTAL'),(3,'landing_title_1','Статистика','Statistics'),(4,'landing_subtitle_1','Основні статистичні показники життя міста','Key statistical indicators of city life'),(5,'landing_title_2','Якість життя','Quality of life'),(6,'landing_subtitle_2','Показники оцінювання якості життя мешканцями міста','Indicators for assessing the quality of life by city residents'),(7,'landing_title_3','Стратегія','Strategy'),(8,'landing_subtitle_3','Показники ефективності виконання Комплексної<br/> стратегії розвитку Львова до 2025 року','Indicators of the effectiveness of implementing the Comprehensive<br/> Development Strategy of Lviv until 2025'),(9,'landing_title_4','інтегрована </br> концепція </br> розвитку ','integrated </br> development </br> concept'),(10,'landing_subtitle_4','Моніторинг показників реалізаціЇ концепції','Monitoring indicators of concept implementation'),(11,'landing_btn','Детальніше','More details'),(12,'about_title_1','Статистика','Statistics'),(13,'about_title_2','Якість життя','Quality of life'),(14,'about_title_3','Стратегія','Strategy'),(15,'about_title_4','ІКР: ЛЬВІВ 2030','ICD: LVIV 2030'),(17,'stat_label_1','Показник:','Indicator:'),(18,'stat_label_2','Надавач даних: ','Data provider:'),(19,'stat_label_3','❮ НАЗАД','❮ BACK'),(20,'stat_label_4','ЗАВАНТАЖИТИ ДАНІ','DOWNLOAD DATA'),(21,'article_1','< Назад до публікації','< Back to publication'),(22,'article_2','Наступна >','Next >'),(23,'article_3','Більше','More'),(100,'about1','<p>Проект «Панель міста» - це відкрита платформа із показниками з різних сфер життя міста.\n\nМетою проекту є створення можливості безперешкодного доступу громадськості до основних показників розвитку міста у зручному форматі.</p><p><br></p>\n\n\n','<p>The \'City Panel\' project is an open platform with indicators from various spheres of city life.\r\n\r\nThe goal of the project is to provide the public with unobstructed access to the main indicators of the city’s development in a convenient format.</p><p><br></p>'),(111,'index1','Основні статистичні показники життя міста','Key statistical indicators of city life'),(113,'index2','Показники оцінювання якості життя мешканцями міста','Indicators for assessing the quality of life by city residents'),(114,'index3','Показники ефективності виконання Комплексної стратегії розвитку Львова до 2025 року\r\n','Indicators of the effectiveness of implementing the Comprehensive Development Strategy of Lviv until 2025'),(116,'about2','Загалом на порталі «Панель міста» можна ознайомитись з даними, які описують такі сфери як населення, бюджет міста, показники економічного розвитку міста, благоустрій, комунальні послуги, транспорт, освіта, охорона здоров’я, безпека, культура, адміністративні послуги тощо, а також переглянути дані в динаміці з 2010 року.','In general, on the \'City Panel\' portal, you can familiarize yourself with data that describe such areas as population, city budget, indicators of the city\'s economic development, amenities, communal services, transport, education, healthcare, safety, culture, administrative services, etc., as well as view data in dynamics starting from 2010.'),(117,'about3','<p>Проект розроблений спільно ЛКП \"Міський центр інформаційних технологій\" Львівської міської ради, Комунальною установою Інститут міста у співпраці з компаніями <a target=\"_blank\" href=\"http://sigma.software/\">Sigma Software</a> та\n					   <a target=\"_blank\" href=\"http://eucalipse.com\">Eucalipse</a> в рамках Програми цифрового перетворення Львова до 2020 року.</p>','<p>The project was developed jointly by LKP \'City Information Technology Center\' of the Lviv City Council, the Municipal Institution \'City Institute\' in cooperation with the companies <a target=\"_blank\" href=\"http://sigma.software/\">Sigma Software</a> and\r\n					   <a target=\"_blank\" href=\"http://eucalipse.com\">Eucalipse</a> within the framework of the Lviv Digital Transformation Program until 2020.</p>'),(118,'about4','Портал «Панель міста» об’єднує понад 800 показників, які структуровані у 4 змістовні блоки:','The \'City Panel\' portal brings together more than 800 indicators structured into 4 thematic blocks:'),(119,'about5','У цьому розділі Ви можете ознайомитись із основними статистичними показниками від різних підрозділів Львівської міської ради, а також інших установ, що описують стан справ в різних сферах життя міста.','In this section, you can familiarize yourself with the main statistical indicators from various subdivisions of the Lviv City Council, as well as other institutions that describe the situation in various spheres of city life.'),(1110,'about6','Показники у цьому розділі відображають суб’єктивні оцінки мешканців щодо якості життя у місті. Показники розраховані згідно з методологією дослідження якості життя у місті, розробленою Інститутом міста та Соціологічною агенцією \"Фама\".','The indicators in this section reflect the subjective assessments of residents regarding the quality of life in the city. The indicators are calculated according to the quality of life research methodology developed by the City Institute and the \'Fama\' Sociological Agency.'),(1111,'about7','Тут Ви можете переглянути показники&nbsp;ефективності реалізації Комплексної стратегії розвитку Львова до 2025 року.<br>','Here you can view the indicators of the effectiveness of implementing the Comprehensive Development Strategy of Lviv until 2025.<br>'),(1112,'footer','<p>© 2016-YEAR. Всі права захищено. Всі права на статті, ілюстрації, інші матеріали належать ЛМР та ЛКП “Міський центр інформаційних технологій” та охороняються Законом України «Про авторське право і суміжні права». При використанні матеріалів посилання на сайт обов\'язкове! Весь контент доступний за ліцензією <a href=\"https://creativecommons.org/licenses/by/4.0/\" style=\"\">Creative Commons Attribution 4.0 International license</a>, якщо не вказано інше.</p>','<p>© 2016-YEAR. All rights reserved. All rights to articles, illustrations, and other materials belong to the Lviv City Council and LKP \"City Information Technology Center\" and are protected by the Law of Ukraine \"On Copyright and Related Rights.\" When using the materials, a link to the website is mandatory! All content is available under the <a href=\"https://creativecommons.org/licenses/by/4.0/\" style=\"\">Creative Commons Attribution 4.0 International license</a>, unless otherwise stated.</p>'),(1120,'footer_1','<b><a href=\"https://city-adm.lviv.ua\" title=\"Офіційний портал. Львівська міська рада\">Львівська міська рада</a></b>\r\n                                <p>\r\n                                    пл. Ринок, 1,\r\n                                    <br>\r\n                                    м. Львів,\r\n                                    <br>\r\n                                    ел. адреса:\r\n                                    <a href=\" mailto:agu@lvivcity.gov.ua\">agu@lvivcity.gov.ua</a>\r\n                                </p>','<b><a href=\"https://city-adm.lviv.ua\" title=\"Official portal. Lviv City Council\">Lviv City Council</a></b>\r\n                                <p>\r\n                                    Rynok Sq., 1,\r\n                                    <br>\r\n                                    Lviv,\r\n                                    <br>\r\n                                    email:\r\n                                    <a href=\" mailto:agu@lvivcity.gov.ua\">agu@lvivcity.gov.ua</a>\r\n                                </p>'),(1121,'footer_2',' <b><a href=\"https://city-adm.lviv.ua/it/\" title=\"ЛКП “Міський центр інформаційних технологій” \">ЛКП “Міський центр IT” </a></b>                                 <p>                                     пл. Ринок, 1, к. 327,                                     <br>                                     м. Львів, 79008                                     <br>                                     тел:                                     <a href=\"tel:+380322545838\">(032) 254-58-38</a><br>ел. адреса:                                     <a href=\"mailto:opendata@lvivcity.gov.ua\">opendata@lvivcity.gov.ua</a>                                 </p>','<b><a href=\"https://city-adm.lviv.ua/it/\" title=\"LKP \'City Information Technology Center\'\">LKP “City IT Center” </a></b>                                 <p>                                     Rynok Sq., 1, rm. 327,                                     <br>                                     Lviv, 79008                                     <br>                                     tel:                                     <a href=\"tel:+380322545838\">(032) 254-58-38</a><br>email:                                     <a href=\"mailto:opendata@lvivcity.gov.ua\">opendata@lvivcity.gov.ua</a>                                 </p>'),(1122,'footer_3','<b><a href=\"http://city-institute.org\" title=\"Інститут міста\">Інститут міста</a></b>                                 <p>                                     пл. Ринок, 1, к. 204,                                     <br>                                     м. Львів, 79008                                     <br>                                     тел/факс                                     <a href=\"tel:+380322546081\">(032) 254-60-81</a><br>                                     ел. адреса                                     <a href=\"mailto:info@city-institute.org\">info@city-institute.org</a>                                 </p>','<b><a href=\"http://city-institute.org\" title=\"City Institute\">City Institute</a></b>                                 <p>                                     Rynok Sq., 1, rm. 204,                                     <br>                                     Lviv, 79008                                     <br>                                     tel/fax                                     <a href=\"tel:+380322546081\">(032) 254-60-81</a><br>                                     email                                     <a href=\"mailto:info@city-institute.org\">info@city-institute.org</a>                                 </p>'),(1124,'stat_label_5','Динаміка','Dynamics'),(1125,'stat_label_6','рік','year'),(1126,'select_category','Виберіть категорію','Select category'),(1127,'header_1','Статистика','Statistics'),(1128,'header_2','Якість життя','Quality of life'),(1129,'header_3','Стратегія','Strategy'),(1130,'header_4','ІКР: ЛЬВІВ 2030','ICD: LVIV 2030'),(1131,'header_5','Публікації','Publications'),(1132,'header_6','Про проект','About the project'),(1133,'landing_url_1','/statystyka/details','/statystyka/details'),(1134,'landing_url_2','/jakist-zyttia/details','/jakist-zyttia/details'),(1135,'landing_url_3','/strategia/details','/strategia/details'),(1136,'landing_url_4','/concepcia/zhytlo','/concepcia/zhytlo'),(1137,'about8','Тут Ви можете переглянути показники інтегрованої концепції розвитку Львова до 2030 року.','Here you can view the indicators of the integrated development concept of Lviv until 2030.');
