LOCK TABLES `stat` WRITE;
/*!40000 ALTER TABLE `stat` DISABLE KEYS */;
INSERT INTO `stat` VALUES (1,239,'1.1.1.1.1','1.1.1.1','Чисельність наявного населення на кінець звітного року (на 1 січня наступного за звітним року)','Number of existing population at the end of the reporting year (as of January 1 of the following year)','Головне управління статистики у Львівській області','Main Department of Statistics in Lviv Region',3,'тис. осіб','thousands of people','<p>Чисельність наявного населення міста Львова (включаючи м. Винники, смт Рудне та смт Брюховичі) на кінець звітного року (на 1 січня наступного за звітним роком), в динаміці із 2010 року<br></p>','<p>Number of available residents of Lviv (including Vynnyky, Rudne, and Bryukhovychi) at the end of the reporting year (as of January 1 of the year following the reporting year), in dynamics since 2010.<br></p>',0,'1','<p><br></p>',NULL,0,'NONE',0,'8c57f5f4-8c6a-4a74-bb8d-2e7b8aa1ae3e','d11ad6b0-4bbb-44cb-862c-86ed67b7c220',750,800,5),(2,239,'1.1.1.1.2','1.1.1.1','Чисельність постійного населення на кінець звітного року','Number of permanent population at the end of the reporting year','Головне управління статистики у Львівській області','Main Department of Statistics in Lviv Region',3,'тис. осіб','thousands of people','<p>Чисельність постійного населення міста Львова на кінець звітного року в динаміці із 2010 року<br></p>','<p>Number of permanent residents of Lviv at the end of the reporting year in dynamics since 2010.<br></p>',0,'1','<p><br></p>',NULL,0,'NONE',0,'8c57f5f4-8c6a-4a74-bb8d-2e7b8aa1ae3e','d11ad6b0-4bbb-44cb-862c-86ed67b7c220',NULL,NULL,NULL),(3,239,'1.1.1.1.3','1.1.1.1','Площа територіальної громади (міста)','Area of the territorial community (city)','Головне управління статистики у Львівській області','Main Department of Statistics in Lviv Region',3,'кв.км','sq. km','<p>Площа територіальної громади (міста) Львова в динаміці із 2010 року<br></p> ','<p>Territorial community area (city) of Lviv in dynamics since 2010.<br></p>',0,'1','<p><br></p>',NULL,0,'NONE',0,'8c57f5f4-8c6a-4a74-bb8d-2e7b8aa1ae3e','d11ad6b0-4bbb-44cb-862c-86ed67b7c220',NULL,NULL,NULL),(4,239,'1.1.1.1.4','1.1.1.1','Густота населення ','Population density','Розрахунковий показник','Calculation Indicator',35,'тис. осіб/кв.км','thousands of people/sq. km','<p>Густота населення міста Львова динаміці із 2010 року (Чисельність постійного населення на кінець звітного року / Площа територіальної громади (міста)<br></p>','<p>Population density of Lviv in dynamics since 2010 (Number of permanent residents at the end of the reporting year / Area of the territorial community (city)).<br></p>',0,'1','<p><br></p>',NULL,1,'{1.1.1.1.2}/{1.1.1.1.3}',0,'8c57f5f4-8c6a-4a74-bb8d-2e7b8aa1ae3e','d11ad6b0-4bbb-44cb-862c-86ed67b7c220',NULL,NULL,NULL),(5,240,'1.1.1.2.1','1.1.1.2','Кількість чоловіків ','Number of men','Головне управління статистики у Львівській області','Main Department of Statistics in Lviv Region',3,'тис. осіб','thousands of people','<p>Кількість осіб чоловічої статі у місті Львові у динаміці із 2010 року.&nbsp;З 2021 року дані не моніторяться.</p>','<p>Number of males in Lviv in dynamics since 2010. Data has not been monitored since 2021.<br></p>',0,'1','<p><br></p>',NULL,0,'NONE',0,'8c57f5f4-8c6a-4a74-bb8d-2e7b8aa1ae3e','d11ad6b0-4bbb-44cb-862c-86ed67b7c220',NULL,NULL,0),(6,240,'1.1.1.2.2','1.1.1.2','Кількість жінок ','Number of women','Головне управління статистики у Львівській області','Main Department of Statistics in Lviv Region',3,'тис. осіб','thousands of people','<p>Частка осіб жіночої статі у місті Львові у динаміці із 2010 року. З 2021 року дані не моніторяться.<br></p>','<p>Share of females in Lviv in dynamics since 2010. Data has not been monitored since 2021.<br></p>',0,'1','<p><br></p>',NULL,0,'NONE',0,'8c57f5f4-8c6a-4a74-bb8d-2e7b8aa1ae3e','d11ad6b0-4bbb-44cb-862c-86ed67b7c220',NULL,NULL,0),(7,240,'1.1.1.2.3','1.1.1.2','Кількість чоловіків на 100 жінок ','Number of men per 100 women','Розрахунковий показник','Calculation Indicator',35,'осіб','people','<p>Співвідношення кількості осіб чоловічої статі із кількістю осіб жіночої статі у Львові в динаміці із 2010 року. З 2021 року дані не моніторяться.<br></p>','<p>Ratio of the number of males to the number of females in Lviv in dynamics since 2010. Data has not been monitored since 2021.<br></p>',0,'1','<p><br></p>',NULL,1,'{1.1.1.2.1}/{1.1.1.2.2}*100',0,'8c57f5f4-8c6a-4a74-bb8d-2e7b8aa1ae3e','d11ad6b0-4bbb-44cb-862c-86ed67b7c220',86,90,0),(8,241,'1.1.1.3.1','1.1.1.3','Кількість населення у віці 0-15 років','Population aged 0-15 years','Головне управління статистики у Львівській області','Main Department of Statistics in Lviv Region',3,'тис. осіб','thousands of people','<p>Кількість населення, у віці від 0 до 15 років включно у місті Львів в динаміці із 2010 року. З 2021 року дані не моніторяться.<br></p>','<p>Number of residents aged 0 to 15 years in Lviv in dynamics since 2010. Data has not been monitored since 2021.<br></p>',0,'1','<p><br></p>',NULL,0,'NONE',0,'8c57f5f4-8c6a-4a74-bb8d-2e7b8aa1ae3e','d11ad6b0-4bbb-44cb-862c-86ed67b7c220',NULL,NULL,0),(9,241,'1.1.1.3.2','1.1.1.3','Кількість населення від 0 до 6 років включно','Population aged 0-6 years inclusive','Головне управління статистики у Львівській області','Main Department of Statistics in Lviv Region',3,'тис. осіб','thousands of people','<p>Кількість населення міста Львова, віком від 0 до 6 років включно в динаміці із 2010 року. З 2021 року дані не моніторяться.<br></p>','<p>Number of residents aged 0 to 6 years in Lviv in dynamics since 2010. Data has not been monitored since 2021.<br></p>',0,'1','<p><br></p>',NULL,0,'NONE',0,'8c57f5f4-8c6a-4a74-bb8d-2e7b8aa1ae3e','d11ad6b0-4bbb-44cb-862c-86ed67b7c220',NULL,NULL,0),(10,241,'1.1.1.3.3','1.1.1.3','Кількість населення віком від 7 до 15 років включно','Population aged 7-15 years inclusive','Головне управління статистики у Львівській області','Main Department of Statistics in Lviv Region',3,'тис. осіб','thousands of people','<p>Кількість населення міста Львова, 